  ('colonel-d0d1b9a2-moex-00092', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司自 X1 年初起租用一建築物作為企業總部，依租約甲公司須自 X1 年起每年年初支付依市場租金水準議定之租金$500,000，租期10年，期滿 該建築物歸還予出租人。甲公司於 X1 年初按其增額借款利率 5%對該租 約認列使用權資產$4,053,911，無殘值，按直線法提列折舊。該租約對甲公 司X10年之本期淨利影響數為（不考慮所得稅，答案四捨五入至元）：', '["$(405,391)", "$(429,201)", "$(451,876)", "$(473,472)"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00093', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '承上題，惟甲公司於 X7 年底將該租約之使用權資產轉列為按公允價值衡 量之投資性不動產，該租約之使用權資產於 X7 年底之公允價值為 $1,284,255。該租約對甲公司X7年之本期淨利影響數為（不考慮所得稅， 答案四捨五入至元）：', '["$(405,391)", "$(429,201)", "$(451,876)", "$(473,472)"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00094', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司採行確定福利退職後計畫，該計畫X1年期初之折現率為10%，服 務成本為$324,000，期初與期末之確定福利義務現值分別為$360,000 與 $720,000，期初與期末之計畫資產公允價值分別為$480,000 與$756,000。 若該計畫之確定福利成本均應計入淨利且經評估淨確定福利資產均無上 限，該計畫對甲公司 X1 年之本期淨利影響數為（不考慮所得稅，答案四 捨五入至元）：', '["$(240,000)", "$(312,000)", "$(320,400)", "$(324,000)"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00095', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '承上題，且經評估淨確定福利資產上限均為$0，該計畫對甲公司 X1 年之 本期淨利影響數為（不考慮所得稅，答案四捨五入至元）：', '["$(240,000)", "$(312,000)", "$(320,400)", "$(324,000)"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
